INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9e3974a1-36ef-454d-b812-b7747fc57bd8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cosmos - Tendermint Consensus: Understanding Height and Block Proposal$escape$,
  $escape$Tendermint consensus in Cosmos relies on a leader-based protocol where each validator node proposes a block. The proposed block undergoes validation and is committed to the blockchain once a majority of validators agree. Height, represented by the `Height` struct in `tendermint/types`, is the primary identifier for a block. It's a 64-bit integer incremented after each block proposal. The `Height` struct also contains a `ChainID` field, which helps identify the specific Cosmos chain. When creating a block proposal, use the `CreateBlock` function from `cosmos-sdk/types` to specify the block's height and chain ID. This ensures the proposal is valid and can be committed to the blockchain.$escape$,
  NULL,
  NULL,
